import csv
from pathlib import Path

class CsvReader:
    """Reads CSV files into a list of dictionaries."""

    def __init__(self, encoding: str = 'utf-8', delimiter: str = ','):
        self.encoding = encoding
        self.delimiter = delimiter

    def read(self, path: Path) -> list[dict]:
        """Read a CSV file and return a list of row dictionaries."""
        with open(path, 'r', encoding=self.encoding, newline='') as f:
            return list(csv.DictReader(f, delimiter=self.delimiter))


class ParquetReader:
    """Reads Parquet files into a list of dictionaries."""

    def __init__(self, columns: list[str] | None = None):
        self.columns = columns

    def read(self, path: Path) -> list[dict]:
        """Read a Parquet file and return a list of row dictionaries."""
        import pyarrow.parquet as pq
        table = pq.read_table(path, columns=self.columns)
        return table.to_pandas().to_dict('records')


