        ...

@dataclass
class StrictValidator:
    """Rejects readings outside the valid range."""
    min_kw: float = 0.0
    max_kw: float = 5000.0

    def validate(self, record: dict) -> tuple[bool, str | None]:
        kw = float(record.get('daily_kw', -1))
        if kw < self.min_kw or kw > self.max_kw:
            return False, f'daily_kw {kw} outside [{self.min_kw}, {self.max_kw}]'
        if not record.get('meter_id'):
            return False, 'missing meter_id'
        return True, None

@dataclass
class LenientValidator:
    """Accepts all readings but flags outliers."""
    warn_min_kw: float = 0.0
    warn_max_kw: float = 5000.0

    def validate(self, record: dict) -> tuple[bool, str | None]:
        kw = float(record.get('daily_kw', 0))
        if kw < self.warn_min_kw or kw > self.warn_max_kw:
            import logging
            logging.getLogger(__name__).warning(
                'Outlier: meter_id=%s daily_kw=%s', record.get('meter_id'), kw
            )
        return True, None  # always valid — analytics wants all data

class BatchValidator:
    """Applies a validation strategy to a batch of records."""
    def __init__(self, strategy: ValidationStrategy):
        self.strategy = strategy

    def validate(self, records: list[dict]) -> tuple[list[dict], list[dict]]:
        valid, rejected = [], []
        for record in records:
            is_valid, reason = self.strategy.validate(record)
            if is_valid:
                valid.append(record)
            else:
                rejected.append({**record, 'reject_reason': reason})
        return valid, rejected

# Billing pipeline: strict validation
billing_validator = BatchValidator(StrictValidator(max_kw=5000))

# Analytics pipeline: lenient validation
analytics_validator = BatchValidator(LenientValidator(warn_max_kw=5000))

