class LocalParquetRepository:
    """Stores data as Parquet files on the local file system."""

    def __init__(self, base_dir: Path):
        self.base_dir = base_dir

    def save(self, records: list[dict], key: str) -> None:
        path = self.base_dir / f'{key}.parquet'
        path.parent.mkdir(parents=True, exist_ok=True)
        import pyarrow as pa, pyarrow.parquet as pq
        table = pa.Table.from_pylist(records)
        pq.write_table(table, path)

    def load(self, key: str) -> list[dict]:
        import pyarrow.parquet as pq
        path = self.base_dir / f'{key}.parquet'
        return pq.read_table(path).to_pandas().to_dict('records')

    def exists(self, key: str) -> bool:
        return (self.base_dir / f'{key}.parquet').exists()

class SilverPipeline:
    def __init__(self, reader: DataReader, validator: DataValidator,
                 silver_repo: DataRepository, quarantine_repo: DataRepository):
        self.reader = reader
        self.validator = validator
        self.silver_repo = silver_repo
        self.quarantine_repo = quarantine_repo

    def run(self, input_path: Path, date: str) -> dict:
        readings = self.reader.read(input_path)
