from concurrent.futures import ThreadPoolExecutor, as_completed
from dataclasses import dataclass, field
import logging

logger = logging.getLogger(__name__)

@dataclass
class ConcurrentResult:
    """Collects successes and failures from concurrent operations."""
    successes: list[tuple[str, list[dict]]] = field(default_factory=list)
    failures: list[tuple[str, Exception]] = field(default_factory=list)

    @property
    def all_records(self) -> list[dict]:
        return [r for _, records in self.successes for r in records]

    @property
    def success_count(self) -> int:
        return len(self.successes)

    @property
    def failure_count(self) -> int:
        return len(self.failures)

def read_files_with_error_collection(
    file_paths: list[Path],
    reader: DataReader,
    max_workers: int = 4,
) -> ConcurrentResult:
    """Read files concurrently, collecting both successes and failures."""
    result = ConcurrentResult()

    with ThreadPoolExecutor(max_workers=max_workers) as pool:
        future_to_path = {pool.submit(reader.read, p): p for p in file_paths}
        for future in as_completed(future_to_path):
            path = future_to_path[future]
            try:
                records = future.result()
                result.successes.append((path.name, records))
            except Exception as e:
                result.failures.append((path.name, e))
                logger.error('Failed to read %s: %s', path.name, e)

    logger.info('Concurrent read: %d succeeded, %d failed',
                result.success_count, result.failure_count)
    return result

