def resolve_execution_order(steps: list[StepDefinition]) -> list[list[str]]:
    """Resolve the DAG into execution layers (steps in the same layer can run concurrently)."""
    step_map = {s.name: s for s in steps}
    remaining = set(step_map.keys())
    completed = set()
    layers = []

    while remaining:
        # Find steps whose dependencies are all completed
        ready = {
            name for name in remaining
            if all(dep in completed for dep in step_map[name].depends_on)
        }
        if not ready:
            unresolved = {n: step_map[n].depends_on for n in remaining}
            raise ValueError(f'Circular dependency detected: {unresolved}')
        layers.append(sorted(ready))
        completed |= ready
        remaining -= ready

    return layers

