import time
import logging
from typing import Any

logger = logging.getLogger(__name__)

class StepRunner:
    """Executes a pipeline step with lifecycle hooks."""

    def __init__(self, hooks: list['StepHook'] | None = None):
        self.hooks = hooks or []

    def run_step(self, step_name: str, component: Any, input_data: Any) -> Any:
        """Execute a step with before/after/error hooks."""
        context = {'step_name': step_name, 'start_time': time.perf_counter()}

        # Before hooks
        for hook in self.hooks:
            hook.before_step(context, input_data)

        try:
            result = component.process(input_data)
            context['success'] = True
            context['duration'] = time.perf_counter() - context['start_time']

            # After hooks (success)
            for hook in self.hooks:
                hook.after_step(context, result)

            return result

        except Exception as e:
            context['success'] = False
            context['error'] = e
            context['duration'] = time.perf_counter() - context['start_time']

            # Error hooks
            for hook in self.hooks:
                hook.on_error(context, e)

            raise

from typing import Protocol, Any

class StepHook(Protocol):
    def before_step(self, context: dict, input_data: Any) -> None: ...
    def after_step(self, context: dict, result: Any) -> None: ...
    def on_error(self, context: dict, error: Exception) -> None: ...

class LoggingHook:
    """Logs step start, completion, and errors."""
    def before_step(self, context: dict, input_data: Any) -> None:
        logger.info('Step %s: started', context['step_name'])

    def after_step(self, context: dict, result: Any) -> None:
        logger.info('Step %s: completed in %.2fs', context['step_name'], context['duration'])

    def on_error(self, context: dict, error: Exception) -> None:
        logger.error('Step %s: failed after %.2fs: %s',
                     context['step_name'], context['duration'], error)

class MetricsHook:
    """Records step metrics for the monitoring dashboard."""
    def __init__(self):
        self.step_metrics: list[dict] = []

    def before_step(self, context: dict, input_data: Any) -> None:
        pass

    def after_step(self, context: dict, result: Any) -> None:
        self.step_metrics.append({
            'step': context['step_name'], 'duration_s': context['duration'],
            'success': True,
        })

    def on_error(self, context: dict, error: Exception) -> None:
        self.step_metrics.append({
            'step': context['step_name'], 'duration_s': context['duration'],
            'success': False, 'error': str(error),
        })

