@dataclass(frozen=True)
class SchemaContract:
    """Declares the required and optional columns a step produces or expects."""
    required_columns: frozenset[str]
    optional_columns: frozenset[str] = frozenset()

    def satisfies(self, expected: 'SchemaContract') -> tuple[bool, list[str]]:
        """Check if this contract satisfies another's requirements."""
        missing = expected.required_columns - self.required_columns - self.optional_columns
        if missing:
            return False, [f'Missing required columns: {missing}']
        return True, []

