# SLOW: string concatenation in a loop — O(n²) because strings are immutable
def build_csv_line_concat(record: dict, columns: list[str]) -> str:
    line = ''
    for col in columns:
        if line:
            line += ','  # creates a new string object each iteration
        line += str(record.get(col, ''))
    return line
# 1.2M calls with 5 columns: 12 seconds

# FAST: list accumulation + join — O(n)
def build_csv_line_join(record: dict, columns: list[str]) -> str:
    return ','.join(str(record.get(col, '')) for col in columns)
