class Registry:
    """Maps string names to factory functions.

    Each registered factory receives a config dict and returns an instance.
    """
    def __init__(self, name: str):
        self.name = name
        self._factories: dict[str, Callable[[dict], Any]] = {}

    def register(self, key: str, factory: Callable[[dict], Any]) -> None:
        """Register a factory under the given name."""
        if key in self._factories:
            logger.warning('Overwriting %s registry entry: %s', self.name, key)
        self._factories[key] = factory
        logger.debug('Registered %s: %s', self.name, key)

    def create(self, key: str, config: dict | None = None) -> Any:
        """Create an instance by name, passing the config to the factory."""
        if key not in self._factories:
            available = ', '.join(sorted(self._factories.keys()))
            raise KeyError(f'Unknown {self.name}: {key!r}. Available: {available}')
        return self._factories[key](config or {})

    @property
    def available(self) -> list[str]:
        return sorted(self._factories.keys())

