import time
import logging
from typing import Any

logger = logging.getLogger(__name__)

class StepRunner:
    """Executes a pipeline step with lifecycle hooks."""

    def __init__(self, hooks: list['StepHook'] | None = None):
        self.hooks = hooks or []

    def run_step(self, step_name: str, component: Any, input_data: Any) -> Any:
        """Execute a step with before/after/error hooks."""
        context = {'step_name': step_name, 'start_time': time.perf_counter()}

        # Before hooks
        for hook in self.hooks:
            hook.before_step(context, input_data)

        try:
            result = component.process(input_data)
            context['success'] = True
            context['duration'] = time.perf_counter() - context['start_time']

            # After hooks (success)
            for hook in self.hooks:
                hook.after_step(context, result)

            return result

        except Exception as e:
            context['success'] = False
            context['error'] = e
            context['duration'] = time.perf_counter() - context['start_time']

            # Error hooks
            for hook in self.hooks:
                hook.on_error(context, e)

            raise

