logger = logging.getLogger(__name__)

class CheckpointManager:
    """Tracks progress for long-running pipelines with file-based checkpoints."""

    def __init__(self, checkpoint_path: Path):
        self.checkpoint_path = checkpoint_path

    def get_last_completed(self) -> str | None:
        """Return the last successfully completed date, or None if no checkpoint."""
        if self.checkpoint_path.exists():
            data = json.loads(self.checkpoint_path.read_text())
            return data.get('last_completed_date')
        return None

    def save(self, completed_date: str) -> None:
        """Save a checkpoint after successfully processing a date."""
        self.checkpoint_path.parent.mkdir(parents=True, exist_ok=True)
        self.checkpoint_path.write_text(json.dumps({
            'last_completed_date': completed_date,
            'checkpoint_time': datetime.now(timezone.utc).isoformat(),
        }))
        logger.info('Checkpoint saved: last_completed=%s', completed_date)

    def clear(self) -> None:
        """Clear the checkpoint after the entire job completes."""
        if self.checkpoint_path.exists():
            self.checkpoint_path.unlink()
            logger.info('Checkpoint cleared')

def run_annual_reprocessing(config: dict) -> dict:
    """Reprocess 365 days with checkpoint-based resume."""
    checkpoint = CheckpointManager(Path(config['checkpoint_path']))
    last_completed = checkpoint.get_last_completed()

    start_date = date.fromisoformat(last_completed) + timedelta(days=1) if last_completed else date(2024, 1, 1)
    end_date = date(2024, 12, 31)

    current = start_date
    while current <= end_date:
        run_silver_pipeline_for_date(config, current.isoformat())
        checkpoint.save(current.isoformat())
        current += timedelta(days=1)

    checkpoint.clear()  # job complete, remove the checkpoint
    return {'days_processed': (end_date - start_date).days + 1}

import signal
import threading
import logging

logger = logging.getLogger(__name__)

class GracefulShutdown:
    """Handles SIGTERM for clean pipeline shutdown."""

    def __init__(self):
        self._shutdown_requested = threading.Event()
        signal.signal(signal.SIGTERM, self._handle_sigterm)
        signal.signal(signal.SIGINT, self._handle_sigterm)  # Ctrl+C in dev

    def _handle_sigterm(self, signum, frame):
        logger.warning('Shutdown requested (signal %d). Finishing current work...', signum)
        self._shutdown_requested.set()

    @property
    def should_stop(self) -> bool:
        return self._shutdown_requested.is_set()

# Usage in the chunked pipeline
def run_chunked_pipeline_with_shutdown(config: dict) -> dict:
    shutdown = GracefulShutdown()
    checkpoint = CheckpointManager(Path(config['checkpoint_path']))

    for chunk in read_csv_in_chunks(config['bronze_path']):
        if shutdown.should_stop:
            logger.info('Shutdown: stopping after current checkpoint')
            break  # exit the loop cleanly

        valid, rejected = validate_readings(chunk)
        write_silver_idempotent(valid, config['silver_path'], config['date'])
        checkpoint.save(config['date'])

    return {'completed': not shutdown.should_stop}
